create table dirkspzm32.isi_res_status (
    sid           varchar2(2 char) not null enable,
    firma_nr      number(*, 0) not null enable,
    res_id        number(*, 0) not null enable,
    st_start      date not null enable,
    st_ende       date,
    res_st_id     number(*, 0) default - 1 not null enable,
    res_typ       varchar2(5 char) not null enable,
    res_st_ug_id  number(*, 0),
    ls_login_id   number(*, 0) not null enable,
    fehler_res_id number(*, 0)
);

alter table dirkspzm32.isi_res_status
    add constraint pk_res_status
        primary key ( sid,
                      firma_nr,
                      res_id,
                      st_start )
            using index enable;


